"},"$:/themes/wikilabs/slant-01/Stylesheet":{"title":"$:/themes/wikilabs/slant-01/Stylesheet","tags":"$:/tags/Stylesheet","type":"text/vnd.tiddlywiki","text":"/* slant-01: compact title row, controls floated to the top-right.
   Scoped to .tc-tiddler-view-frame so the EditTemplate is left alone. */

.tc-tiddler-view-frame .tc-tiddler-title {
	position: relative;
}

.tc-tiddler-view-frame .tc-tiddler-title .tc-titlebar {
	display: flex;
	flex-wrap: wrap;
	align-items: baseline;
	column-gap: 1em;
	row-gap: 0.1em;
	padding-right: 7em;
	margin-bottom: 1em;
	font-size: 1.1em;
}

.tc-tiddler-view-frame .tc-tiddler-title > .tc-tiddler-controls {
	position: absolute;
	top: 0;
	right: 0;
	font-size: 2em;
}

.tc-tiddler-view-frame .tc-tiddler-title .tc-tiddler-title-icon {
	margin-inline-end: 0.35em;
}

.tc-tiddler-view-frame .tc-tiddler-title > .tc-tiddler-controls .tc-image-button {
	vertical-align: top;
}

.tc-tiddler-view-frame .tc-tiddler-title > .tc-tiddler-controls .tc-drop-down .tc-image-button {
	vertical-align: unset;
}

.tc-tiddler-view-frame .tc-titlebar .wltc-subtitle {
	font-size: 0.7em;
	white-space: nowrap;
}

.tc-tiddler-view-frame .tc-tags-wrapper {
	padding-top: 2px;
	margin-top: -0.4em;
	margin-bottom: 0.3em;
}

.tc-tiddler-view-frame .tc-tiddler-body {
	border-top: thin solid lightgray;
}

.tc-tiddler-view-frame .tc-tiddler-info {
	padding-right: 12px;
}
"},"$:/core/ui/TagTemplate":{"title":"$:/core/ui/TagTemplate","text":"\whitespace trim
<span class="tc-tag-list-item" data-tag-title=<<currentTiddler>>>
	<$let tabState={{{ [[$:/state/infotab/]addsuffix<storyTiddler>] }}}>
		<$macrocall $name="tag-pill-body"
			tag=<<currentTiddler>>
			icon={{{ [<currentTiddler>] :cascade[all[shadows+tiddlers]tag[$:/tags/TiddlerIconFilter]!is[draft]get[text]] }}}
			colour={{{ [<currentTiddler>] :cascade[all[shadows+tiddlers]tag[$:/tags/TiddlerColourFilter]!is[draft]get[text]] }}}
			palette={{$:/palette}}
			element-tag="$button"
			element-attributes="""tag='span'"""
			actions="""<$action-setfield $tiddler=<<tiddlerInfoState>> text="yes"/><$action-setfield $tiddler=<<tabState>> text="$:/wikilabs/ui/TiddlerInfo/TagMap"/>"""
		/>
	</$let>
</span>
